1	const PROCESSING_FEE = 5;
2	
3	type Step = { op: "quote"; items: { type: string }[] };
4	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	export const run = (input: unknown): unknown => {
7	  const { steps } = input as Input;
8	  const results = steps.map((step) => {
9	    if (step.items.length === 0) return { premium: PROCESSING_FEE };
10	    return { premium: 115 };
11	  });
12	  return { results };
13	};
14

